import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  RadialLinearScale,
  Filler
} from 'chart.js';
import { Bar, Line, Doughnut, Radar } from 'react-chartjs-2';
import './App.css';

// Register ChartJS components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  RadialLinearScale,
  Filler,
  Title,
  Tooltip,
  Legend
);

const API_BASE = 'http://localhost:5000/api';

// Professional color scheme
const COLORS = {
  primary: '#6366f1',
  secondary: '#8b5cf6',
  success: '#10b981',
  warning: '#f59e0b',
  danger: '#ef4444',
  dark: '#1e293b',
  darker: '#0f172a',
  light: '#64748b',
  lighter: '#cbd5e1'
};

function App() {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [analysisMode, setAnalysisMode] = useState('individual');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // Individual analysis state
  const [customerData, setCustomerData] = useState({
    Tenure: 12.0,
    OrderCount: 8.0,
    CashbackAmount: 15000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 25.0,
    OrderAmountHikeFromlastYear: 12.0,
    CouponUsed: 3,
    NumberOfDeviceRegistered: 2,
    Complain: 0,
    SatisfactionScore: 4,
    WarehouseToHome: 15.0,
    NumberOfAddress: 3,
    CityTier: 2,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Married'
  });

  const [batchFile, setBatchFile] = useState(null);

  const handleInputChange = (field, value) => {
    setCustomerData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleIndividualAnalysis = async () => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_BASE}/analyze-single`, {
        customer_data: customerData
      });
      setResults(response.data);
      setActiveTab('results');
    } catch (error) {
      console.error('Analysis error:', error);
      alert('Error analyzing customer data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const handleBatchAnalysis = async () => {
    if (!batchFile) {
      alert('Please select a file');
      return;
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('file', batchFile);

    try {
      const response = await axios.post(`${API_BASE}/analyze-batch`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      setBatchResults(response.data);
      setActiveTab('batch-results');
    } catch (error) {
      console.error('Batch analysis error:', error);
      alert('Error analyzing batch data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  return (
    <div className="app">
      {/* Sidebar */}
      <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <div className="sidebar-header">
          <div className="logo">
            <div className="logo-icon">📊</div>
            <div className="logo-text">
              <div className="logo-title">ChurnIntel</div>
              <div className="logo-subtitle">Enterprise</div>
            </div>
          </div>
          <button 
            className="sidebar-toggle"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            {sidebarOpen ? '◀' : '▶'}
          </button>
        </div>

        <nav className="sidebar-nav">
          <div className="nav-section">
            <div className="nav-label">MAIN</div>
            <button 
              className={`nav-item ${activeTab === 'dashboard' ? 'active' : ''}`}
              onClick={() => setActiveTab('dashboard')}
            >
              <span className="nav-icon">🏠</span>
              {sidebarOpen && <span className="nav-text">Dashboard</span>}
            </button>
            <button 
              className={`nav-item ${activeTab === 'analyze' ? 'active' : ''}`}
              onClick={() => setActiveTab('analyze')}
            >
