// Analyze View Component
const AnalyzeView = ({ 
  customerData, 
  onInputChange, 
  onAnalyze, 
  loading, 
  analysisMode, 
  setAnalysisMode,
  onFileChange,
  onBatchAnalyze 
}) => {
  const [activeSection, setActiveSection] = useState('basic');

  const renderInputField = (label, field, type = 'number', options = null) => {
    if (type === 'select') {
      return (
        <div className="form-group">
          <label className="form-label">{label}</label>
          <select 
            className="form-select"
            value={customerData[field]} 
            onChange={(e) => onInputChange(field, e.target.value)}
          >
            {options.map(option => (
              <option key={option} value={option}>{option}</option>
            ))}
          </select>
        </div>
      );
    }

    if (type === 'toggle') {
      return (
        <div className="form-group">
          <label className="form-label">{label}</label>
          <div className="toggle-group">
            <button 
              type="button"
              className={`toggle-btn ${customerData[field] ? 'active' : ''}`}
              onClick={() => onInputChange(field, 1)}
            >
              Yes
            </button>
            <button 
              type="button"
              className={`toggle-btn ${!customerData[field] ? 'active' : ''}`}
              onClick={() => onInputChange(field, 0)}
            >
              No
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="form-group">
        <label className="form-label">{label}</label>
        <input 
          className="form-input"
          type={type}
          value={customerData[field]}
          onChange={(e) => onInputChange(field, parseFloat(e.target.value) || e.target.value)}
          step={type === 'number' ? 'any' : undefined}
        />
      </div>
    );
  };

  return (
    <div className="analyze-view">
      {/* Mode Selection */}
      <div className="mode-selection">
        <div className="mode-tabs">
          <button 
            className={`mode-tab ${analysisMode === 'individual' ? 'active' : ''}`}
            onClick={() => setAnalysisMode('individual')}
