            </button>
            <button 
              className={`section-tab ${activeSection === 'demographic' ? 'active' : ''}`}
              onClick={() => setActiveSection('demographic')}
            >
              Demographics
            </button>
          </div>

          {/* Form Sections */}
          <div className="form-sections">
            {activeSection === 'basic' && (
              <div className="form-section">
                <div className="form-columns">
                  <div className="form-column">
