                    {renderInputField("Cashback Amount (₹)", "CashbackAmount")}
                    {renderInputField("Days Since Last Order", "DaySinceLastOrder")}
                  </div>
                  <div className="form-column">
                    {renderInputField("Satisfaction Score (1-5)", "SatisfactionScore", "number")}
                    {renderInputField("Warehouse Distance (km)", "WarehouseToHome")}
                    {renderInputField("City Tier", "CityTier", "number")}
