// Risk Gauge Component
const RiskGauge = ({ probability }) => {
  const pct = probability * 100;

  const data = {
    labels: ['Low', 'Medium', 'High'],
    datasets: [
      {
        data: [30, 40, 30],
        backgroundColor: ['#10b981', '#f59e0b', '#ef4444'],
        borderWidth: 0,
        circumference: 180,
        rotation: 270,
      },
    ],
  };

  const options = {
    plugins: {
      legend: { display: false },
      tooltip: { enabled: false },
    },
    cutout: '70%',
    maintainAspectRatio: false,
  };

  return (
    <div className="gauge-container">
      <Doughnut data={data} options={options} />
      <div className="gauge-center">
        <div className="gauge-value">{pct.toFixed(1)}%</div>
        <div className="gauge-label">RISK</div>
      </div>
    </div>
  );
};

// Feature Chart Component
const FeatureChart = ({ contributions }) => {
  const topFeatures = contributions.slice(0, 8);

  const data = {
    labels: topFeatures.map(f => f.Feature),
    datasets: [
      {
        data: topFeatures.map(f => f.Contribution * 100),
        backgroundColor: '#6366f1',
        borderColor: '#4f46e5',
        borderWidth: 1,
      },
    ],
  };

  const options = {
    indexAxis: 'y',
    plugins: {
      legend: { display: false },
    },
    scales: {
      x: {
        grid: { color: '#334155' },
        ticks: { color: '#94a3b8' },
      },
      y: {
        grid: { color: '#334155' },
        ticks: { color: '#cbd5e1' },
      },
    },
  };

  return (
    <div className="chart-container">
      <Bar data={data} options={options} />
    </div>
  );
};

